function solve(nums1) {
    const n = nums1.length;

    if (n === 1) {
        // If N=1, nums2[0] must be nums1[0]. It trivially satisfies the condition.
        return true;
    }

    // If N >= 2, we rely on the parity counts derived from analyzing the choices.
    let countOdd = 0;
    for (const num of nums1) {
        if (num % 2 !== 0) {
            countOdd++;
        }
    }

    // The construction is possible if and only if the count of odd numbers is not exactly 1.
    // If countOdd = 0 or countOdd >= 2, at least one target parity (all even or all odd) can be achieved.
    return countOdd !== 1;
}

